15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.numeric_std.all;
18	
19	library surf;
20	use surf.StdRtlPkg.all;
21	
22	package Jesd204bPkg is
23	
24	   --------------------------------------------------------------------------
25	   -- Constant definitions
26	   --------------------------------------------------------------------------
27	   -- Number of bytes in MGT word (2 or 4).
28	   constant GT_WORD_SIZE_C : positive := 4;
29	
30	   -- 8B10B characters (8-bit values)
31	   -- K.28.5
32	   constant K_CHAR_C : slv(7 downto 0) := x"BC";
33	   -- K.28.0
34	   constant R_CHAR_C : slv(7 downto 0) := x"1C";
35	   -- K.28.3
36	   constant A_CHAR_C : slv(7 downto 0) := x"7C";
37	   -- K.28.7
38	   constant F_CHAR_C : slv(7 downto 0) := x"FC";
39	
40	   -- Register or counter widths
41	   constant SYSRF_DLY_WIDTH_C : positive := 8;
42	   constant RX_STAT_WIDTH_C   : positive := 19 + 2*GT_WORD_SIZE_C;
43	   constant TX_STAT_WIDTH_C   : positive := 6;
44	
45	   -- AXI packet size at power up
46	   constant AXI_PACKET_SIZE_DEFAULT_C : slv(23 downto 0) := x"00_01_00";
47	
48	   -- TX specific
49	
50	   -- Ramp step or square wave period slv width (max 16)
51	   constant PER_STEP_WIDTH_C : positive := 16;
52	
53	   -- Scrambler/Descrambler PBRS taps for 1 + x^14 + x^15
54	   constant JESD_PRBS_TAPS_C : NaturalArray := (0 => 14, 1 => 15);
55	
56	   --------------------------------------------------------------------------
57	   -- Sub-types
58	   --------------------------------------------------------------------------
59	   type JesdGtRxLaneType is record
60	      data      : slv((GT_WORD_SIZE_C*8)-1 downto 0);  -- PHY receive data
61	      dataK     : slv(GT_WORD_SIZE_C-1 downto 0);  -- PHY receive data is K character
62	      dispErr   : slv(GT_WORD_SIZE_C-1 downto 0);  -- PHY receive data has disparity error
63	      decErr    : slv(GT_WORD_SIZE_C-1 downto 0);  -- PHY receive data not in table
64	      rstDone   : sl;
65	      cdrStable : sl;
66	   end record JesdGtRxLaneType;
67	
68	   constant JESD_GT_RX_LANE_INIT_C : JesdGtRxLaneType := (
69	      data      => (others => '0'),
70	      dataK     => (others => '0'),
71	      dispErr   => (others => '0'),
72	      decErr    => (others => '0'),
73	      rstDone   => '0',
74	      cdrStable => '0');
75	
76	   type JesdGtTxLaneType is record
77	      data  : slv((GT_WORD_SIZE_C*8)-1 downto 0);  -- PHY receive data
78	      dataK : slv(GT_WORD_SIZE_C-1 downto 0);  -- PHY receive data is K character
79	   end record JesdGtTxLaneType;
80	   constant JESD_GT_TX_LANE_INIT_C : JesdGtTxLaneType := (
81	      data  => (others => '0'),
82	      dataK => (others => '0'));
83	
84	   -- Arrays
85	   type JesdGtRxLaneTypeArray is array (natural range <>) of JesdGtRxLaneType;
86	   type JesdGtTxLaneTypeArray is array (natural range <>) of JesdGtTxLaneType;
87	   type FixLatDataArray is array (natural range <>) of slv((GT_WORD_SIZE_C*8+GT_WORD_SIZE_C*2)-1 downto 0);
88	   type SampleDataArray is array (natural range <>) of slv((GT_WORD_SIZE_C*8)-1 downto 0);
89	   type SampleDataVectorArray is array (natural range<>, natural range<>) of slv((GT_WORD_SIZE_C*8)-1 downto 0);
90	   type RxStatuRegisterArray is array (natural range <>) of slv((RX_STAT_WIDTH_C)-1 downto 0);
91	   type TxStatuRegisterArray is array (natural range <>) of slv((TX_STAT_WIDTH_C)-1 downto 0);
92	   type AlignTxArray is array (natural range <>) of slv((GT_WORD_SIZE_C)-1 downto 0);
93	
94	   --------------------------------------------------------------------------
95	   -- Functions
96	   --------------------------------------------------------------------------
97	
98	   -- Detect K character
99	   function detKcharFunc(data_slv : slv; charisk_slv : slv; bytes_int : positive) return std_logic;
100	
101	   -- Output variable index from SLV (use in variable length shift register)
102	   function varIndexOutFunc(shft_slv : slv; index_slv : slv) return std_logic;
103	
104	   -- Detect position of first non K character (Swapped)
105	   function detectPosFuncSwap(data_slv : slv; charisk_slv : slv; bytes_int : positive) return std_logic_vector;
106	
107	   -- Detect position of first non K character
108	   function detectPosFunc(data_slv : slv; charisk_slv : slv; bytes_int : positive) return std_logic_vector;
109	
110	   -- Byte swap slv (bytes int 2 or 4)
111	   function byteSwapSlv(data_slv : slv; bytes_int : positive) return std_logic_vector;
112	
113	   -- Swap little and big endians (bytes int 2 or 4)
114	   function endianSwapSlv(data_slv : slv; bytes_int : positive) return std_logic_vector;
115	
116	   -- Align the data within the data buffer according to the position of the byte alignment word
117	   function JesdDataAlign(data_slv : slv; position_slv : slv; bytes_int : positive) return std_logic_vector;
118	
119	   -- Align the character within the buffer according to the position of the byte alignment word
120	   function JesdCharAlign(char_slv : slv; position_slv : slv; bytes_int : positive) return std_logic_vector;
121	
122	   -- Convert standard logic vector to integer
123	   function slvToInt(data_slv : slv) return integer;
124	
125	   -- Convert integer to standard logic vector
126	   function intToSlv(data_int : integer; bytes_int : positive) return std_logic_vector;
127	
128	   -- Output offset binary zero
129	   function outSampleZero(F_int : positive; bytes_int : positive) return std_logic_vector;
130	
131	   -- Invert functions
132	
133	   -- Invert signed
134	   function invSigned(input : slv) return std_logic_vector;
135	   function invData(data    : slv; F_int : positive; bytes_int : positive) return std_logic_vector;
136	
137	   procedure jesdScrambler (
138	      dataIn  : in    slv(15 downto 0);
139	      lfsrIn  : in    slv(14 downto 0);
140	      dataOut : inout slv(15 downto 0);
141	      lfsrOut : inout slv(14 downto 0));
142	
143	end package Jesd204bPkg;
144	
145	package body Jesd204bPkg is
146	
147	   --------------------------------------------------------------------------
148	   -- Functions
149	   --------------------------------------------------------------------------
150	
151	   -- Detect K character
152	   function detKcharFunc(data_slv : slv; charisk_slv : slv; bytes_int : positive) return std_logic is
153	   begin
154	      if(bytes_int = 2) then
155	         if(data_slv (7 downto 0) = K_CHAR_C and
156	            data_slv (15 downto 8) = K_CHAR_C and
157	            charisk_slv = (charisk_slv'range => '1')
158	            ) then
159	            return '1';
160	         else
161	            return '0';
162	         end if;
163	      elsif(bytes_int = 4) then
164	         if(data_slv (7 downto 0) = K_CHAR_C and
165	            data_slv (15 downto 8) = K_CHAR_C and
166	            data_slv (23 downto 16) = K_CHAR_C and
167	            data_slv (31 downto 24) = K_CHAR_C and
168	            charisk_slv = (charisk_slv'range => '1')
169	            ) then
170	            return '1';
171	         else
172	            return '0';
173	         end if;
174	      else
175	         return '0';
176	      end if;
177	   end function detKcharFunc;
178	
179	   -- Output variable index from SLV (use in variable length shift register)
180	   function varIndexOutFunc(shft_slv : slv; index_slv : slv) return std_logic is
181	      variable i : integer;
182	   begin
183	      -- Return the index
184	      i := to_integer(unsigned(index_slv));
185	      return shft_slv(i);
186	
187	   end function varIndexOutFunc;
188	
189	   -- Detect position of first non K character
190	   function detectPosFunc(data_slv : slv; charisk_slv : slv; bytes_int : positive) return std_logic_vector is
191	   begin
192	      -- GT word is 2 bytes
193	      if(bytes_int = 2) then
194	         if(data_slv (7 downto 0) /= K_CHAR_C and
195	            data_slv (15 downto 8) /= K_CHAR_C
196	            ) then
197	            return "01";
198	         elsif(data_slv (7 downto 0) /= K_CHAR_C and
199	               data_slv (15 downto 8) = K_CHAR_C and
200	               charisk_slv(1) = '1'
201	               ) then
202	            return "10";
203	         else
204	            return "11";
205	         end if;
206	      -- GT word is 4 bytes wide
207	      elsif(bytes_int = 4) then
208	         if(data_slv (7 downto 0) /= K_CHAR_C and
209	            data_slv (15 downto 8) /= K_CHAR_C and
210	            data_slv (23 downto 16) /= K_CHAR_C and
211	            data_slv (31 downto 24) /= K_CHAR_C
212	            ) then
213	            return "0001";
214	         elsif(data_slv (7 downto 0) /= K_CHAR_C and
215	               data_slv (15 downto 8) /= K_CHAR_C and
216	               data_slv (23 downto 16) /= K_CHAR_C and
217	               data_slv (31 downto 24) = K_CHAR_C and
218	               charisk_slv(3) = '1'
219	               ) then
220	            return "0010";
221	         elsif(data_slv (7 downto 0) /= K_CHAR_C and
222	               data_slv (15 downto 8) /= K_CHAR_C and
223	               data_slv (23 downto 16) = K_CHAR_C and
224	               data_slv (31 downto 24) = K_CHAR_C and
225	               charisk_slv(3 downto 2) = "11"
226	               ) then
227	            return "0100";
228	         elsif(data_slv (7 downto 0) /= K_CHAR_C and
229	               data_slv (15 downto 8) = K_CHAR_C and
230	               data_slv (23 downto 16) = K_CHAR_C and
231	               data_slv (31 downto 24) = K_CHAR_C and
232	               charisk_slv(3 downto 1) = "111"
233	               ) then
234	            return "1000";
235	         else
236	            return "1111";
237	         end if;
238	      else
239	         return (bytes_int-1 downto 0 => '1');
240	      end if;
241	   end function detectPosFunc;
242	
243	
244	   -- Detect position of first non K character (Swapped bits/bytes)
245	   function detectPosFuncSwap(data_slv : slv; charisk_slv : slv; bytes_int : positive) return std_logic_vector is
246	   begin
247	      -- GT word is 2 bytes
248	      if(bytes_int = 2) then
249	         if(data_slv (7 downto 0) /= K_CHAR_C and
250	            data_slv (15 downto 8) /= K_CHAR_C
251	            ) then
252	            return "01";
253	         elsif(data_slv (7 downto 0) = K_CHAR_C and
254	               data_slv (15 downto 8) /= K_CHAR_C and
255	               charisk_slv(0) = '1'
256	               ) then
257	            return "10";
258	         else
259	            return "11";
260	         end if;
261	      -- GT word is 4 bytes wide
262	      elsif(bytes_int = 4) then
263	         if(data_slv (7 downto 0) /= K_CHAR_C and
264	            data_slv (15 downto 8) /= K_CHAR_C and
265	            data_slv (23 downto 16) /= K_CHAR_C and
266	            data_slv (31 downto 24) /= K_CHAR_C
267	            ) then
268	            return "0001";
269	         elsif(data_slv (7 downto 0) = K_CHAR_C and
270	               data_slv (15 downto 8) /= K_CHAR_C and
271	               data_slv (23 downto 16) /= K_CHAR_C and
272	               data_slv (31 downto 24) /= K_CHAR_C and
273	               charisk_slv(0) = '1'
274	               ) then
275	            return "0010";
276	         elsif(data_slv (7 downto 0) = K_CHAR_C and
277	               data_slv (15 downto 8) = K_CHAR_C and
278	               data_slv (23 downto 16) /= K_CHAR_C and
279	               data_slv (31 downto 24) /= K_CHAR_C and
280	               charisk_slv(1 downto 0) = "11"
281	               ) then
282	            return "0100";
283	         elsif(data_slv (7 downto 0) = K_CHAR_C and
284	               data_slv (15 downto 8) = K_CHAR_C and
285	               data_slv (23 downto 16) = K_CHAR_C and
286	               data_slv (31 downto 24) /= K_CHAR_C and
287	               charisk_slv(2 downto 0) = "111"
288	               ) then
289	            return "1000";
290	         else
291	            return "1111";
292	         end if;
293	      else
294	         return (bytes_int-1 downto 0 => '1');
295	      end if;
296	   end function detectPosFuncSwap;
297	
298	   -- Byte swap slv (bytes int 2 or 4)
299	   function byteSwapSlv(data_slv : slv; bytes_int : positive) return std_logic_vector is
300	   begin
301	
302	      if(bytes_int = 2) then
303	         return data_slv(7 downto 0) & data_slv(15 downto 8);
304	      elsif(bytes_int = 4) then
305	         return data_slv(7 downto 0) & data_slv(15 downto 8) & data_slv(23 downto 16) & data_slv(31 downto 24);
306	      else
307	         return data_slv;
308	      end if;
309	   end function byteSwapSlv;
310	
311	   -- Swap little or big endian (bytes int 2 or 4)
312	   function endianSwapSlv(data_slv : slv; bytes_int : positive) return std_logic_vector is
313	   begin
314	
315	      if(bytes_int = 2) then
316	         return data_slv;
317	      elsif(bytes_int = 4) then
318	         return data_slv(15 downto 0) & data_slv(31 downto 16);
319	      else
320	         return data_slv;
321	      end if;
322	   end function endianSwapSlv;
323	
324	   -- Align the data within the data buffer according to the position of the byte alignment word
325	   function JesdDataAlign(data_slv : slv; position_slv : slv; bytes_int : positive) return std_logic_vector is
326	   begin
327	      if(bytes_int = 2) then
328	         if (position_slv(1 downto 0) = "01") then
329	            return data_slv (31 downto 16);
330	         elsif (position_slv(1 downto 0) = "10") then
331	            return data_slv (31-8 downto 16-8);
332	         else
333	            return data_slv (31 downto 16);
334	         end if;
335	      elsif(bytes_int = 4) then
336	         if (position_slv(3 downto 0) = "0001") then
337	            return data_slv(63 downto 32);
338	         elsif (position_slv(3 downto 0) = "0010") then
339	            return data_slv(63-1*8 downto 32-1*8);
340	         elsif (position_slv(3 downto 0) = "0100") then
341	            return data_slv(63-2*8 downto 32-2*8);
342	         elsif (position_slv(3 downto 0) = "1000") then
343	            return data_slv(63-3*8 downto 32-3*8);
344	         else
345	            return data_slv(63 downto 32);
346	         end if;
347	      else
348	         return data_slv;
349	      end if;
350	   end function JesdDataAlign;
351	
352	   -- Align the char within the buffer according to the position of the byte alignment word
353	   function JesdCharAlign(char_slv : slv; position_slv : slv; bytes_int : positive) return std_logic_vector is
354	   begin
355	      if(bytes_int = 2) then
356	         if (position_slv(1 downto 0) = "01") then
357	            return char_slv (3 downto 2);
358	         elsif (position_slv(1 downto 0) = "10") then
359	            return char_slv (3-1 downto 2-1);
360	         else
361	            return char_slv (3 downto 2);
362	         end if;
363	      elsif(bytes_int = 4) then
364	         if (position_slv(3 downto 0) = "0001") then
365	            return char_slv(7 downto 4);
366	         elsif (position_slv(3 downto 0) = "0010") then
367	            return char_slv(7-1 downto 4-1);
368	         elsif (position_slv(3 downto 0) = "0100") then
369	            return char_slv(7-2 downto 4-2);
370	         elsif (position_slv(3 downto 0) = "1000") then
371	            return char_slv(7-3 downto 4-3);
372	         else
373	            return char_slv(7 downto 4);
374	         end if;
375	      else
376	         return char_slv;
377	      end if;
378	   end function JesdCharAlign;
379	
380	   -- Convert standard logic vector to integer
381	   function slvToInt(data_slv : slv) return integer is
382	   begin
383	      return to_integer(unsigned(data_slv));
384	   end function slvToInt;
385	
386	   -- Convert integer to standard logic vector
387	   function intToSlv(data_int : integer; bytes_int : positive) return std_logic_vector is
388	   begin
389	      return std_logic_vector(to_unsigned(data_int, bytes_int));
390	   end function IntToSlv;
391	
392	   -- Output zero sample data depending on word size and Frame size
393	   function outSampleZero(F_int : positive; bytes_int : positive) return std_logic_vector is
394	      constant SAMPLES_IN_WORD_C : positive := (bytes_int/F_int);
395	      variable vSlv              : slv((bytes_int*8)-1 downto 0);
396	   begin
397	
398	      vSlv := (others => '0');
399	
400	      for i in (SAMPLES_IN_WORD_C-1) downto 0 loop
401	         vSlv(i*8*F_int+8*F_int-1) := '1';
402	      end loop;
403	
404	      return vSlv;
405	
406	   end function outSampleZero;
407	
408	   -- Invert Signed
409	   function invSigned(input : slv) return std_logic_vector is
410	      variable vOutput : signed(input'range);
411	   begin
412	      vOutput := - signed(input);
413	      return std_logic_vector(vOutput);
414	   end function invSigned;
415	
416	   -- Output zero sample data depending on word size and Frame size
417	   function invData(data : slv; F_int : positive; bytes_int : positive) return std_logic_vector is
418	      constant SAMPLES_IN_WORD_C : positive := (bytes_int/F_int);
419	      variable vSlv              : slv((bytes_int*8)-1 downto 0);
420	   begin
421	
422	      vSlv := data;
423	
424	      for i in (SAMPLES_IN_WORD_C-1) downto 0 loop
425	         vSlv(i*8*F_int+8*F_int-1 downto i*8*F_int) := invSigned(vSlv(i*8*F_int+8*F_int-1 downto i*8*F_int));
426	      end loop;
427	
428	      return vSlv;
429	
430	   end function invData;
431	
432	   -- lfsr(14:0)=1+x^14+x^15
433	   procedure jesdScrambler (
434	      dataIn  : in    slv(15 downto 0);
435	      lfsrIn  : in    slv(14 downto 0);
436	      dataOut : inout slv(15 downto 0);
437	      lfsrOut : inout slv(14 downto 0)) is
438	   begin
439	      lfsrOut(0)  := lfsrIn(0) xor lfsrIn(1) xor lfsrIn(2) xor lfsrIn(3) xor lfsrIn(4) xor lfsrIn(5) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13);
440	      lfsrOut(1)  := lfsrIn(0) xor lfsrIn(1) xor lfsrIn(2) xor lfsrIn(3) xor lfsrIn(4) xor lfsrIn(5) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
441	      lfsrOut(2)  := lfsrIn(1) xor lfsrIn(2) xor lfsrIn(3) xor lfsrIn(4) xor lfsrIn(5) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
442	      lfsrOut(3)  := lfsrIn(2) xor lfsrIn(3) xor lfsrIn(4) xor lfsrIn(5) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
443	      lfsrOut(4)  := lfsrIn(3) xor lfsrIn(4) xor lfsrIn(5) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
444	      lfsrOut(5)  := lfsrIn(4) xor lfsrIn(5) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
445	      lfsrOut(6)  := lfsrIn(5) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
446	      lfsrOut(7)  := lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
447	      lfsrOut(8)  := lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
448	      lfsrOut(9)  := lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
449	      lfsrOut(10) := lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
450	      lfsrOut(11) := lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
451	      lfsrOut(12) := lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
452	      lfsrOut(13) := lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
453	      lfsrOut(14) := lfsrIn(0) xor lfsrIn(1) xor lfsrIn(2) xor lfsrIn(3) xor lfsrIn(4) xor lfsrIn(5) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(14);
454	
455	      dataOut(0)  := dataIn(0) xor lfsrIn(14);
456	      dataOut(1)  := dataIn(1) xor lfsrIn(13) xor lfsrIn(14);
457	      dataOut(2)  := dataIn(2) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
458	      dataOut(3)  := dataIn(3) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
459	      dataOut(4)  := dataIn(4) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
460	      dataOut(5)  := dataIn(5) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
461	      dataOut(6)  := dataIn(6) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
462	      dataOut(7)  := dataIn(7) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
463	      dataOut(8)  := dataIn(8) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
464	      dataOut(9)  := dataIn(9) xor lfsrIn(5) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
465	      dataOut(10) := dataIn(10) xor lfsrIn(4) xor lfsrIn(5) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
466	      dataOut(11) := dataIn(11) xor lfsrIn(3) xor lfsrIn(4) xor lfsrIn(5) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
467	      dataOut(12) := dataIn(12) xor lfsrIn(2) xor lfsrIn(3) xor lfsrIn(4) xor lfsrIn(5) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
468	      dataOut(13) := dataIn(13) xor lfsrIn(1) xor lfsrIn(2) xor lfsrIn(3) xor lfsrIn(4) xor lfsrIn(5) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
469	      dataOut(14) := dataIn(14) xor lfsrIn(0) xor lfsrIn(1) xor lfsrIn(2) xor lfsrIn(3) xor lfsrIn(4) xor lfsrIn(5) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13) xor lfsrIn(14);
470	      dataOut(15) := dataIn(15) xor lfsrIn(0) xor lfsrIn(1) xor lfsrIn(2) xor lfsrIn(3) xor lfsrIn(4) xor lfsrIn(5) xor lfsrIn(6) xor lfsrIn(7) xor lfsrIn(8) xor lfsrIn(9) xor lfsrIn(10) xor lfsrIn(11) xor lfsrIn(12) xor lfsrIn(13);
471	
472	   end procedure;
473	
474	end package body Jesd204bPkg;
