1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description: JesdRx single lane module
5	--              Receiver JESD204b standard.
6	--              Supports sub-class 1 deterministic latency.
7	--              Supports sub-class 0 non deterministic latency
8	--              Features:
9	--              - Comma synchronization
10	--              - Internal buffer to align the lanes.
11	--              - Sample data alignment (Sample extraction from GT word - barrel shifter).
12	--              - Alignment character replacement.
13	--              - Scrambling support
14	--             Status register encoding:
15	--                bit 0: GT Reset done
16	--                bit 1: Received data valid
17	--                bit 2: Received data is misaligned
18	--                bit 3: Synchronization output status
19	--                bit 4: Rx buffer overflow
20	--                bit 5: Rx buffer underflow
21	--                bit 6: Comma position not as expected during alignment
22	--                bit 7: RX module enabled status
23	--                bit 8: SysRef detected (active only when the lane is enabled)
24	--                bit 9: Comma (K28.5) detected
25	--                bit 10-13: Disparity error
26	--                bit 14-17: Not in table Error
27	--                bit 18-25: 8-bit buffer latency
28	--                bit 26: CDR Status of the GTH (Not used in yaml)
29	--
30	--          Note: sampleData_o is little endian and not byte swapped
31	--                First sample in time:  sampleData_o(15 downto 0)
32	--                Second sample in time: sampleData_o(31 downto 16)
33	--
34	--          Note: The output ADC sample data can be inverted.
35	--                     inv_i:     '1' Inverted,      '0' Normal
36	--                If inverted the mode can be chosen:
37	--                     invMode_i: '1' Offset binary, '0' Twos complement
38	-------------------------------------------------------------------------------
39	-- This file is part of 'SLAC Firmware Standard Library'.
40	-- It is subject to the license terms in the LICENSE.txt file found in the
41	-- top-level directory of this distribution and at:
42	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
43	-- No part of 'SLAC Firmware Standard Library', including this file,
44	-- may be copied, modified, propagated, or distributed except according to
45	-- the terms contained in the LICENSE.txt file.
46	-------------------------------------------------------------------------------
47	
48	library ieee;
49	use ieee.std_logic_1164.all;
50	use ieee.std_logic_arith.all;
51	use ieee.std_logic_unsigned.all;
52	
53	
54	library surf;
55	use surf.StdRtlPkg.all;
56	use surf.Jesd204bPkg.all;
57	
58	entity JesdRxLane is
59	   generic (
60	      TPD_G : time     := 1 ns;
61	      -- Number of bytes in a frame
62	      F_G   : positive := 2;
63	      -- Number of frames in a multi frame
64	      K_G   : positive := 32);
65	   port (
66	      -- Clocks and Resets
67	      devClk_i      : in  sl;
68	      devRst_i      : in  sl;
69	      -- JESD subclass selection: '0' or '1'(default)
70	      subClass_i    : in  sl;
71	      -- SYSREF for subclass 1 fixed latency
72	      sysRef_i      : in  sl;
73	      -- Clear registered errors
74	      clearErr_i    : in  sl;
75	      -- Control register
76	      enable_i      : in  sl;
77	      replEnable_i  : in  sl;
78	      scrEnable_i   : in  sl;
79	      status_o      : out slv((RX_STAT_WIDTH_C)-1 downto 0);
80	      -- Data and character inputs from GT (transceivers)
81	      r_jesdGtRx    : in  jesdGtRxLaneType;
82	      -- Local multi frame clock
83	      lmfc_i        : in  sl;
84	      -- Error mask
85	      linkErrMask_i : in  slv(5 downto 0) := (others => '1');
86	      -- One or more RX modules requested synchronization
87	      nSyncAny_i    : in  sl;
88	      nSyncAnyD1_i  : in  sl;
89	      -- Invert ADC data
90	      inv_i         : in  sl              := '0';
91	      -- Synchronization request output
92	      nSync_o       : out sl;
93	      -- Synchronization process is complete and data is valid
94	      dataValid_o   : out sl;
95	      sampleData_o  : out slv((GT_WORD_SIZE_C*8)-1 downto 0));
96	end JesdRxLane;
97	
98	architecture rtl of JesdRxLane is
99	
100	   constant ERR_REG_WIDTH_C : positive := 4+2*GT_WORD_SIZE_C;
101	
102	
103	   type RegType is record
104	      bufWeD1         : sl;
105	      errReg          : slv(ERR_REG_WIDTH_C-1 downto 0);
106	      sampleData      : slv(sampleData_o'range);
107	      sampleDataValid : sl;
108	      jesdGtRx        : jesdGtRxLaneType;
109	   end record RegType;
110	   constant REG_INIT_C : RegType := (
111	      bufWeD1         => '0',
112	      errReg          => (others => '0'),
113	      sampleData      => (others => '0'),
114	      sampleDataValid => '0',
115	      jesdGtRx        => JESD_GT_RX_LANE_INIT_C);
116	
117	   signal r   : RegType := REG_INIT_C;
118	   signal rin : RegType;
119	
120	
121	   -- Control signals from FSM
122	   signal s_nSync          : sl;
123	   signal s_readBuff       : sl;
124	   signal s_alignFrame     : sl;
125	   signal s_alignFrameDly1 : sl;
126	   signal s_alignFrameDly0 : sl;
127	   signal s_ila            : sl;
128	   signal s_dataValid      : sl;
129	   signal s_dataValidDly1  : sl;
130	   signal s_dataValidDly0  : sl;
131	
132	   -- Buffer control
133	   signal s_bufRst : sl;
134	   signal s_bufWe  : sl;
135	   signal s_bufRe  : sl;
136	
137	   -- Data path
138	   signal s_charAndData         : slv(((GT_WORD_SIZE_C*8)+GT_WORD_SIZE_C)-1 downto 0);
139	   signal s_charAndDataBuff     : slv(s_charAndData'range);
140	   signal s_charAndDataBuffDly1 : slv(s_charAndData'range);
141	   signal s_charAndDataBuffDly0 : slv(s_charAndData'range);
142	   signal s_sampleData          : slv(sampleData_o'range);
143	   signal s_sampleDataValid     : sl;
144	
145	   -- Statuses
146	   signal s_bufOvf      : sl;
147	   signal s_bufUnf      : sl;
148	   signal s_bufFull     : sl;
149	   signal s_alignErr    : sl;
150	   signal s_positionErr : sl;
151	   signal s_linkErrVec  : slv(5 downto 0);
152	   signal s_linkErr     : sl;
153	   signal s_kDetected   : sl;
154	   signal s_refDetected : sl;
155	   signal s_errComb     : slv(ERR_REG_WIDTH_C-1 downto 0);
156	   signal s_buffLatency : slv(7 downto 0);
157	
158	begin
159	
160	   s_charAndData <= r.jesdGtRx.dataK & r.jesdGtRx.data;
161	
162	   -----------------
163	   -- Buffer control
164	   -----------------
165	   s_bufRst <= devRst_i or not s_nSync or not enable_i;
166	   s_bufWe  <= not s_bufRst and not s_bufFull;
167	   s_bufRe  <= r.bufWeD1 and s_readBuff;
168	
169	   -----------------------------------------------------------------------
170	   -- Buffer samples between first data and LMFC Min size one LMFC period
171	   -----------------------------------------------------------------------
172	   RX_buffer_fifo_INST : entity surf.FifoSync
173	      generic map (
174	         TPD_G          => TPD_G,
175	         RST_POLARITY_G => '1',
176	         RST_ASYNC_G    => false,
177	         MEMORY_TYPE_G  => "block",
178	         FWFT_EN_G      => false,
179	         PIPE_STAGES_G  => 0,
180	         DATA_WIDTH_G   => (GT_WORD_SIZE_C*8) + GT_WORD_SIZE_C,
181	         -- ADDR_WIDTH_G   => bitSize((K_G * F_G)/GT_WORD_SIZE_C),
182	         ADDR_WIDTH_G   => 8,
183	         INIT_G         => "0",
184	         FULL_THRES_G   => 1,
185	         EMPTY_THRES_G  => 1)
186	      port map (
187	         rst        => s_bufRst,
188	         clk        => devClk_i,
189	         wr_en      => s_bufWe,         -- Always write when enabled
190	         rd_en      => s_bufRe,  -- Hold read while sync not in sync with LMFC
191	         din        => s_charAndData,
192	         dout       => s_charAndDataBuff,
193	         data_count => s_buffLatency,
194	         overflow   => s_bufOvf,
195	         underflow  => s_bufUnf,
196	         full       => s_bufFull);
197	
198	   ----------------------
199	   -- Synchronization FSM
200	   ----------------------
201	   syncFSM_INST : entity surf.JesdSyncFsmRx
202	      generic map (
203	         TPD_G => TPD_G,
204	         F_G   => F_G,
205	         K_G   => K_G)
206	      port map (
207	         clk          => devClk_i,
208	         rst          => devRst_i,
209	         enable_i     => enable_i,
210	         sysRef_i     => sysRef_i,
211	         dataRx_i     => r.jesdGtRx.data,
212	         chariskRx_i  => r.jesdGtRx.dataK,
213	         gtReady_i    => r.jesdGtRx.rstDone,
214	         lmfc_i       => lmfc_i,
215	         nSyncAnyD1_i => nSyncAnyD1_i,
216	         nSyncAny_i   => nSyncAny_i,
217	         linkErr_i    => s_linkErr,
218	         nSync_o      => s_nSync,
219	         readBuff_o   => s_readBuff,
220	         alignFrame_o => s_alignFrame,
221	         ila_o        => s_ila,
222	         kDetected_o  => s_kDetected,
223	         sysref_o     => s_refDetected,
224	         dataValid_o  => s_dataValid,
225	         subClass_i   => subClass_i);
226	
227	   ------------------------------------------------------------------
228	   -- Align the rx data within the GT word and replace the characters
229	   ------------------------------------------------------------------
230	   alignFrRepCh_INST : entity surf.JesdAlignFrRepCh
231	      generic map (
232	         TPD_G => TPD_G,
233	         F_G   => F_G)
234	      port map (
235	         clk               => devClk_i,
236	         rst               => devRst_i,
237	         replEnable_i      => replenable_i,
238	         scrEnable_i       => scrEnable_i,
239	         alignFrame_i      => s_alignFrameDly1,
240	         dataValid_i       => s_dataValidDly1,
241	         dataRx_i          => s_charAndDataBuffDly1((GT_WORD_SIZE_C*8)-1 downto 0),
242	         chariskRx_i       => s_charAndDataBuffDly1(((GT_WORD_SIZE_C*8)+GT_WORD_SIZE_C)-1 downto (GT_WORD_SIZE_C*8)),
243	         sampleDataValid_o => s_sampleDataValid,
244	         sampleData_o      => s_sampleData,
245	         alignErr_o        => s_alignErr,
246	         positionErr_o     => s_positionErr);
247	
248	   process(devClk_i)
249	   begin
250	      if rising_edge(devClk_i) then
251	
252	         -- Register to help with timing
253	         s_alignFrameDly1      <= s_alignFrameDly0      after TPD_G;
254	         s_dataValidDly1       <= s_dataValidDly0       after TPD_G;
255	         s_charAndDataBuffDly1 <= s_charAndDataBuffDly0 after TPD_G;
256	
257	         -- Register to help with timing
258	         s_alignFrameDly0      <= s_alignFrame      after TPD_G;
259	         s_dataValidDly0       <= s_dataValid       after TPD_G;
260	         s_charAndDataBuffDly0 <= s_charAndDataBuff after TPD_G;
261	
262	         -- Link error masked by the mask from register and ORed
263	         s_linkErrVec <= s_positionErr & s_bufOvf & s_bufUnf & uOr(r.jesdGtRx.dispErr) & uOr(r.jesdGtRx.decErr) & s_alignErr after TPD_G;
264	         s_linkErr    <= uOr(s_linkErrVec and linkErrMask_i) and enable_i                                                    after TPD_G;
265	
266	         -- Combine errors that need registering
267	         s_errComb <= r.jesdGtRx.decErr & r.jesdGtRx.dispErr & s_alignErr & s_positionErr & s_bufOvf & s_bufUnf after TPD_G;
268	
269	      end if;
270	   end process;
271	
272	   comb : process (clearErr_i, enable_i, inv_i, r, r_jesdGtRx, s_bufWe,
273	                   s_buffLatency, s_dataValidDly1, s_errComb, s_kDetected,
274	                   s_nSync, s_refDetected, s_sampleData, s_sampleDataValid) is
275	      variable v : RegType;
276	   begin
277	      -- Latch the current value
278	      v := r;
279	
280	      -- Keep a delayed copy
281	      v.jesdGtRx := r_jesdGtRx;
282	      v.bufWeD1  := s_bufWe;
283	
284	      -- Register errors (store until reset)
285	      if (r.jesdGtRx.rstDone = '1' and s_nSync = '1') then
286	         for i in 0 to(ERR_REG_WIDTH_C-1) loop
287	            if (s_errComb(i) = '1') and (enable_i = '1') then
288	               v.errReg(i) := '1';
289	            end if;
290	         end loop;
291	      end if;
292	
293	      -- Clear registered errors if module is disabled
294	      if (clearErr_i = '1') then
295	         v.errReg := REG_INIT_C.errReg;
296	      end if;
297	
298	      -- Invert sample data
299	      v.sampleDataValid := s_sampleDataValid;
300	
301	      -- Check if inverting the data
302	      if (inv_i = '1') then
303	         -- Invert sample data
304	         v.sampleData := invData(s_sampleData, F_G, GT_WORD_SIZE_C);
305	
306	         -- +1 correction (https://jira.slac.stanford.edu/browse/ESLMPS-94)
307	         for i in F_G-1 downto 0 loop
308	            v.sampleData(i*8*F_G+8*F_G-1 downto i*8*F_G) := v.sampleData(i*8*F_G+8*F_G-1 downto i*8*F_G) - 1;
309	         end loop;
310	
311	      else
312	         v.sampleData := s_sampleData;
313	      end if;
314	
315	      -- Register the variable for next clock cycle
316	      rin <= v;
317	
318	      -- Output assignment
319	      nSync_o      <= s_nSync;
320	      dataValid_o  <= r.sampleDataValid;
321	      sampleData_o <= endianSwapSlv(r.sampleData, GT_WORD_SIZE_C);
322	      status_o     <= r.jesdGtRx.cdrStable & s_buffLatency & r.errReg(r.errReg'high downto 4) & s_kDetected & s_refDetected & enable_i & r.errReg(2 downto 0) & s_nSync & r.errReg(3) & s_dataValidDly1 & r.jesdGtRx.rstDone;
323	
324	   end process comb;
325	
326	   seq : process (devClk_i) is
327	   begin
328	      if (rising_edge(devClk_i)) then
329	         r <= rin after TPD_G;
330	      end if;
331	   end process seq;
332	
333	end rtl;
334

