27	entity JesdSyncFsmRx is
28	   generic (
29	      TPD_G : time := 1 ns;
30	
31	      -- Number of bytes in a frame
32	      F_G : positive := 2;
33	
34	      -- Number of frames in a multi frame
35	      K_G : positive := 32;
36	
37	      -- Number of multi-frames in ILA sequence (4-255)
38	      NUM_ILAS_MF_G : positive := 4);
39	   port (
40	      -- Clocks and Resets
41	      clk : in sl;
42	      rst : in sl;
43	
44	      -- Enable the module
45	      enable_i  : in sl;
46	      gtReady_i : in sl;
47	
48	      -- JESD subclass selection: '0' or '1'(default)
49	      subClass_i : in sl;
50	
51	      -- SYSREF for subcalss 1 fixed latency
52	      sysRef_i : in sl;
53	
54	      -- Data and character inputs from GT (transceivers)
55	      dataRx_i    : in slv((GT_WORD_SIZE_C*8)-1 downto 0);
56	      chariskRx_i : in slv(GT_WORD_SIZE_C-1 downto 0);
57	
58	      -- Local multi frame clock
59	      lmfc_i : in sl;
60	
61	      -- One or more RX modules requested synchronization
62	      nSyncAny_i   : in sl;
63	      nSyncAnyD1_i : in sl;
64	
65	      -- Combined link errors
66	      linkErr_i : in sl;
67	
68	      -- Synchronous FSM control outputs
69	
70	      -- Synchronization request
71	      nSync_o : out sl;
72	
73	      -- Elastic buffer latency in clock cycles
74	      buffLatency_o : out slv(7 downto 0);
75	
76	      -- Read enable for Rx Buffer.
77	      -- Holds buffers between first data and LMFC
78	      readBuff_o : out sl;
79	
80	      -- First non comma (K) character detected.
81	      -- To indicate when to realign sample within the dataRx.
82	      alignFrame_o : out sl;
83	
84	      -- Ila frames are being received
85	      ila_o : out sl;
86	
87	      -- K detected
88	      kDetected_o : out sl;
89	
90	      -- sysref received
91	      sysref_o : out sl;
92	
93	      -- Synchronisation process is complete and data is valid
94	      dataValid_o : out sl);
95	end JesdSyncFsmRx;
96	
97	architecture rtl of JesdSyncFsmRx is
98	
99	   type StateType is (
100	      IDLE_S,
101	      SYSREF_S,
102	      SYNC_S,
103	      HOLD_S,
104	      ALIGN_S,
105	      ILA_S,
106	      DATA_S);
107	
108	   type RegType is record
109	      -- Synchronous FSM control outputs
110	      kDetectRegD1 : sl;
111	      kDetectRegD2 : sl;
112	      kDetectRegD3 : sl;
113	
114	      linkErr    : sl;
115	      nSync      : sl;
116	      readBuff   : sl;
117	      alignFrame : sl;
118	      Ila        : sl;
119	      dataValid  : sl;
120	      sysref     : sl;
121	      cnt        : slv(7 downto 0);
122	      cntLatency : slv(7 downto 0);
123	
124	      -- Status Machine
125	      state : StateType;
126	   end record RegType;
127	
128	   constant REG_INIT_C : RegType := (
129	      kDetectRegD1 => '0',
130	      kDetectRegD2 => '0',
131	      kDetectRegD3 => '0',
132	
133	      linkErr    => '0',
134	      nSync      => '0',
135	      readBuff   => '0',
136	      alignFrame => '0',
137	      Ila        => '0',
138	      dataValid  => '0',
139	      sysref     => '0',
140	      cnt        => (others => '0'),
141	      cntLatency => (others => '0'),
142	
143	      -- Status Machine
144	      state => IDLE_S);
145	
146	   signal r   : RegType := REG_INIT_C;
147	   signal rin : RegType;
148	
149	   signal s_kDetected : sl;
150	   signal s_kStable   : sl;
151	
152	begin
153	
154	   s_kDetected <= detKcharFunc(dataRx_i, chariskRx_i, GT_WORD_SIZE_C);
155	   -- Comma detected if detected in three consecutive clock cycles
156	   s_kStable   <= s_kDetected and r.kDetectRegD1 and r.kDetectRegD2 and r.kDetectRegD3;
157	
158	   -- State machine
159	   comb : process (chariskRx_i, dataRx_i, enable_i, gtReady_i, linkErr_i,
160	                   lmfc_i, nSyncAnyD1_i, nSyncAny_i, r, rst, s_kDetected,
161	                   s_kStable, subClass_i, sysRef_i) is
162	      variable v : RegType;
163	   begin
164	      -- Latch the current value
165	      v := r;
166	
167	      -- Comma detected pipeline
168	      v.kDetectRegD1 := detKcharFunc(dataRx_i, chariskRx_i, GT_WORD_SIZE_C);
169	      v.kDetectRegD2 := r.kDetectRegD1;
170	      v.kDetectRegD3 := r.kDetectRegD2;
171	      --
172	      v.linkErr      := linkErr_i;
173	
174	      -- State Machine
175	      case r.state is
176	         ----------------------------------------------------------------------
177	         when IDLE_S =>
178	
179	            -- Outputs
180	            v.nSync      := '0';
181	            v.readBuff   := '1';
182	            v.alignFrame := '0';
183	            v.Ila        := '0';
184	            v.dataValid  := '0';
185	            v.sysref     := '0';
186	            v.cntLatency := (others => '0');
187	
188	            -- Next state condition (depending on subclass)
189	            if subClass_i = '1' then
190	               if sysRef_i = '1' and enable_i = '1' and nSyncAnyD1_i = '0' and gtReady_i = '1' and s_kStable = '1' then
191	                  v.state := SYSREF_S;
192	               end if;
193	            else
194	               if enable_i = '1' and gtReady_i = '1' and s_kStable = '1' then
195	                  v.state := SYSREF_S;
196	               end if;
197	            end if;
198	         ----------------------------------------------------------------------
199	         when SYSREF_S =>
200	
201	            -- Outputs
202	            v.nSync      := '0';
203	            v.readBuff   := '1';
204	            v.alignFrame := '0';
205	            v.Ila        := '0';
206	            v.dataValid  := '0';
207	            v.sysref     := '1';
208	            v.cntLatency := (others => '0');
209	
210	            -- Next state condition
211	            if s_kDetected = '1' and lmfc_i = '1' then
212	               v.state := SYNC_S;
213	            elsif enable_i = '0' then
214	               v.state := IDLE_S;
215	            end if;
216	         ----------------------------------------------------------------------
217	         when SYNC_S =>
218	
219	            -- Outputs
220	            v.nSync      := '1';
221	            v.readBuff   := '1';
222	            v.alignFrame := '0';
223	            v.Ila        := '0';
224	            v.dataValid  := '0';
225	            v.sysref     := '1';
226	            v.cntLatency := (others => '0');
227	
228	            -- Next state condition
229	            if s_kDetected = '0' then
230	               v.state := HOLD_S;
231	            -- v.readBuff   := '0'; -- TODO this signal has to be applied one c-c earlier for simulation
232	            -- But in hardware that is not the case. This should be investigated.
233	            elsif enable_i = '0' then
234	               v.state := IDLE_S;
235	            end if;
236	         ----------------------------------------------------------------------
237	         when HOLD_S =>
238	
239	            -- Outputs
240	            v.nSync      := '1';
241	            v.readBuff   := '0';
242	            v.alignFrame := '0';
243	            v.Ila        := '0';
244	            v.dataValid  := '0';
245	            v.sysref     := '1';
246	            v.cntLatency := r.cntLatency + 1;
247	
248	            -- Next state condition
249	            if lmfc_i = '1' then
250	               v.state := ALIGN_S;
251	            elsif enable_i = '0' then
252	               v.state := IDLE_S;
253	            end if;
254	
255	         ----------------------------------------------------------------------
256	         when ALIGN_S =>
257	
258	            -- Outputs
259	            v.nSync      := '1';
260	            v.readBuff   := '1';
261	            v.alignFrame := '1';
262	            v.Ila        := '1';
263	            v.dataValid  := '0';
264	            v.sysref     := '1';
265	            v.cntLatency := r.cntLatency;
266	
267	            -- Put ILA Sequence counter to 0
268	            v.cnt := (others => '0');
269	
270	            -- Next state condition
271	            v.state := ILA_S;
272	
273	         ----------------------------------------------------------------------
274	         when ILA_S =>
275	            -- Outputs
276	            v.nSync      := '1';
277	            v.readBuff   := '1';
278	            v.alignFrame := '0';
279	            v.Ila        := '1';
280	            v.dataValid  := '0';
281	            v.sysref     := '1';
282	            v.cntLatency := r.cntLatency;
283	
284	            -- Increase lmfc counter.
285	            if (lmfc_i = '1') then
286	               v.cnt := r.cnt + 1;
287	            end if;
288	
289	            -- Next state condition
290	            -- After NUM_ILAS_MF_G LMFC clocks the ILA sequence ends and relevant ADC data is being received.
291	            if r.cnt = NUM_ILAS_MF_G then
292	               v.state := DATA_S;
293	            elsif enable_i = '0' or s_kStable = '1' then
294	               v.state := IDLE_S;
295	            end if;
296	         ----------------------------------------------------------------------
297	         when DATA_S =>
298	            -- Outputs
299	            v.nSync      := '1';
300	            v.readBuff   := '1';
301	            v.alignFrame := '0';
302	            v.Ila        := '0';
303	            v.dataValid  := '1';
304	            v.sysref     := '1';
305	            v.cntLatency := r.cntLatency;
306	
307	            -- Next state condition
308	            if nSyncAny_i = '0' or r.linkErr = '1' or enable_i = '0' or s_kStable = '1' or gtReady_i = '0' then
309	               v.state := IDLE_S;
310	            end if;
311	         ----------------------------------------------------------------------
312	         when others =>
313	            -- Outputs
314	            v.nSync      := '0';
315	            v.readBuff   := '0';
316	            v.alignFrame := '0';
317	            v.Ila        := '0';
318	            v.dataValid  := '0';
319	            v.sysref     := '0';
320	            v.cntLatency := (others => '0');
321	
322	            -- Next state condition
323	            v.state := IDLE_S;
324	      ----------------------------------------------------------------------
325	      end case;
326	
327	      -- Synchronous Reset
328	      if rst = '1' then
329	         v := REG_INIT_C;
330	      end if;
331	
332	      -- Register the variable for next clock cycle
333	      rin <= v;
334	
335	   end process comb;
336	
337	   seq : process (clk) is
338	   begin
339	      if rising_edge(clk) then
340	         r <= rin after TPD_G;
341	      end if;
342	   end process seq;
343	
344	   -- Output assignment
345	   nSync_o       <= r.nSync;
346	   readBuff_o    <= r.readBuff;
347	   alignFrame_o  <= r.alignFrame;
348	   Ila_o         <= r.Ila;
349	   dataValid_o   <= r.dataValid;
350	   kDetected_o   <= s_kStable;
351	   sysref_o      <= r.sysref;
352	   buffLatency_o <= r.cntLatency;
353	
354	end rtl;
