31	   constant CLK_PERIOD_C : time := 1 us;  -- 1 us makes it easy to count clock cycles in sim GUI
32	   constant TPD_G        : time := CLK_PERIOD_C/4;
33	
34	   constant EN_SCRAMBLER_C : boolean := true;
35	
36	   --------------------------------------------------------
37	   -- BYTE_SHIFT_C=0: JesdRx.JesdAlignChGen.position="0001"
38	   -- BYTE_SHIFT_C=1: JesdRx.JesdAlignChGen.position="1000"
39	   -- BYTE_SHIFT_C=2: JesdRx.JesdAlignChGen.position="0100"
