37	entity JesdAlignFrRepCh is
38	   generic (
39	      TPD_G : time := 1 ns;
40	
41	      -- Number of bytes in a frame
42	      F_G : positive := 2);
43	   port (
44	      clk : in sl;
45	      rst : in sl;
46	
47	      -- Enable character replacement
48	      replEnable_i : in sl;
49	
50	      -- Enable scrambling/descrambling
51	      scrEnable_i : in sl;
52	
53	      -- One c-c long pulse from syncFSM indicating that first non K
54	      -- character has been received
55	      alignFrame_i : in sl;
56	
57	      -- Data ready (replace control character with data when '1')
58	      dataValid_i : in sl;
59	
60	      -- Data and character indication
61	      dataRx_i    : in slv((GT_WORD_SIZE_C*8)-1 downto 0);
62	      chariskRx_i : in slv(GT_WORD_SIZE_C-1 downto 0);
63	
64	      -- Sample data output (after alignment, character replacement and scrambling)
65	      sampleData_o      : out slv((GT_WORD_SIZE_C*8)-1 downto 0);
66	      sampleDataValid_o : out sl;
67	
68	      -- Alignment and sync position errors
69	      alignErr_o    : out sl;   -- Invalid or misaligned character in the data
70	      positionErr_o : out sl);  -- Invalid (comma) position received at time of alignment
71	end entity JesdAlignFrRepCh;
72	
73	architecture rtl of JesdAlignFrRepCh is
74	
75	   -- How many samples is in a GT word
76	   constant SAMPLES_IN_WORD_C : positive := (GT_WORD_SIZE_C/F_G);
77	
78	   type RegType is record
79	      dataRxD1       : slv(dataRx_i'range);
80	      chariskRxD1    : slv(chariskRx_i'range);
81	      dataAlignedD1  : slv(dataRx_i'range);
82	      charAlignedD1  : slv(chariskRx_i'range);
83	      scrData        : slv(sampleData_o'range);
84	      scrDataValid   : sl;
85	      lfsr           : slv((GT_WORD_SIZE_C*8)-1 downto 0);
86	      descrData      : slv((GT_WORD_SIZE_C*8)-1 downto 0);
87	      descrDataValid : sl;
88	      sampleData     : slv(sampleData_o'range);
89	      dataValid      : sl;
90	      position       : slv(chariskRx_i'range);
91	   end record RegType;
92	
93	   constant REG_INIT_C : RegType := (
94	      dataRxD1       => (others => '0'),
95	      chariskRxD1    => (others => '0'),
96	      dataAlignedD1  => (others => '0'),
97	      charAlignedD1  => (others => '0'),
98	      scrData        => (others => '0'),
99	      lfsr           => (others => '0'),
100	      descrData      => (others => '0'),
101	      scrDataValid   => '0',
102	      sampleData     => (others => '0'),
103	      descrDataValid => '0',
104	      dataValid      => '0',
105	      position       => intToSlv(1, GT_WORD_SIZE_C));  -- Initialize at "0001" or "01"
106	
107	   signal r   : RegType := REG_INIT_C;
108	   signal rin : RegType;
109	
110	begin
111	
112	   -- Buffer two GT words (Sequential logic)
113	   -- Register the alignment position when alignFrame_i pulse
114	   -- Incorrect alignment (non valid data word received) will result in
115	   -- v.position = (others => '1')
116	   ---------------------------------------------------------------------
117	   ---------------------------------------------------------------------
118	   comb : process (alignFrame_i, chariskRx_i, dataRx_i, dataValid_i, r,
119	                   replEnable_i, rst, scrEnable_i) is
120	      variable v : RegType;
121	
122	      -- Alignment error. Invalid data received at time of alignment
123	      variable vPositionErr   : sl;
124	      variable vAlignErr      : sl;
125	      variable vTwoWordbuff   : slv((GT_WORD_SIZE_C*16)-1 downto 0);
126	      variable vTwoCharBuff   : slv((GT_WORD_SIZE_C*2) -1 downto 0);
127	      variable vTwoWordbuffAl : slv((GT_WORD_SIZE_C*16)-1 downto 0);
128	      variable vTwoCharBuffAl : slv((GT_WORD_SIZE_C*2) -1 downto 0);
129	      variable vDataaligned   : slv(dataRx_i'range);
130	      variable vCharAligned   : slv(chariskRx_i'range);
131	
132	   begin
133	
134	      v := r;
135	
136	      -- Buffer data and char one clock cycle
137	      v.dataRxD1    := dataRx_i;
138	      v.chariskRxD1 := chariskRx_i;
139	
140	      -- Buffer aligned data
141	      v.dataAlignedD1 := vDataaligned;
142	      v.charAlignedD1 := vCharAligned;
143	
144	      -- Register the alignment
145	      if (alignFrame_i = '1') then
146	         v.position := detectPosFuncSwap(dataRx_i, chariskRx_i, GT_WORD_SIZE_C);
147	      end if;
148	
149	      -- Align samples (Combinatorial logic)
150	
151	      -- Check position error (if position vector "1111" is returned)
152	      vPositionErr := ite(allBits (r.position, '1'), '1', '0');
153	
154	      -- Byte swap and combine the two consecutive GT words
155	      vTwoWordbuff := byteSwapSlv(r.dataRxD1, GT_WORD_SIZE_C) & byteSwapSlv(dataRx_i, GT_WORD_SIZE_C);
156	      vTwoCharBuff := bitReverse(r.chariskRxD1) & bitReverse(chariskRx_i);
157	
158	      -- Align the bytes within the words
159	      vDataaligned := JesdDataAlign(vTwoWordbuff, r.position, GT_WORD_SIZE_C);
160	      vCharAligned := JesdCharAlign(vTwoCharBuff, r.position, GT_WORD_SIZE_C);
161	
162	      -- Buffer aligned word and replace the alignment characters with the data
163	      vTwoWordbuffAl := r.dataAlignedD1 & vDataaligned;
164	      vTwoCharBuffAl := r.charAlignedD1 & vCharAligned;
165	      vAlignErr      := '0';
166	
167	      -- Replace the control characters in the data with valid data
168	      if(replEnable_i = '1' and dataValid_i = '1') then
169	         for i in (SAMPLES_IN_WORD_C-1) downto 0 loop
170	            -- If the A_CHAR_C or F_CHAR_C characters detected in the stream
171	            if (vTwoCharBuffAl(i*F_G) = '1' and
172	                (vTwoWordBuffAl((i*F_G*8+7) downto i*F_G*8) = A_CHAR_C or
173	                 vTwoWordBuffAl((i*F_G*8+7) downto i*F_G*8) = F_CHAR_C)
174	                ) then
175	               -- If scrambling disabled
176	               -- Replace the character in the data with the data value from previous frame
177	               if (scrEnable_i = '0') then
178	                  vTwoWordbuffAl((i*F_G*8+7) downto i*F_G*8) := vTwoWordBuffAl((i*F_G*8+8*F_G)+7 downto (i*F_G*8+8*F_G));
179	                  vTwoCharBuffAl(i*F_G)                      := '0';
180	               -- If scrambling enabled
181	               -- The data value equals char value and only the char flags are cleared
182	               else
183	                  vTwoWordbuffAl        := vTwoWordbuffAl;
184	                  vTwoCharBuffAl(i*F_G) := '0';
185	               end if;
186	            end if;
187	         end loop;
188	      end if;
189	
190	      -- Check character if there are still characters in the data and issue the alignment error
191	      -- The error indicates that the characters in the data are possibly misplaced or wrong characters
192	      -- have been received.
193	      if(replEnable_i = '1' and dataValid_i = '1') then
194	         for i in (GT_WORD_SIZE_C-1) downto 0 loop
195	            if (vTwoCharBuffAl(i) = '1') then
196	               vAlignErr := '1';
197	            end if;
198	         end loop;
199	      end if;
200	
201	      -- Register data before scrambling
202	      v.scrData        := vTwoWordBuffAl((GT_WORD_SIZE_C*8)-1 downto 0);
203	      v.scrDataValid   := dataValid_i;
204	      v.descrDataValid := r.scrDataValid;
205	
206	      -- Descramble data put data into descrambler MSB first
207	      -- Start descrambling when data is enabled
208	      if (scrEnable_i = '1' and r.scrDataValid = '1') then
209	         for i in (GT_WORD_SIZE_C*8)-1 downto 0 loop
210	            v.lfsr         := v.lfsr(v.lfsr'left-1 downto v.lfsr'right) & r.scrData(i);
211	            --
212	            v.descrData(i) := r.scrData(i);
213	            for j in JESD_PRBS_TAPS_C'range loop
214	               v.descrData(i) := v.descrData(i) xor v.lfsr(JESD_PRBS_TAPS_C(j));
215	            end loop;
216	         --
217	         end loop;
218	      else
219	         v.descrData := r.scrData;
220	      end if;
221	
222	      -- Register sample data before output (Prevent timing issues! Adds one clock cycle to latency!)
223	      if (scrEnable_i = '1') then
224	         -- 3 c-c latency
225	         v.sampleData := r.descrData;
226	         v.dataValid  := r.descrDataValid;
227	      else
228	         -- 1 c-c latency
229	         v.sampleData := vTwoWordBuffAl((GT_WORD_SIZE_C*8)-1 downto 0);
230	         v.dataValid  := dataValid_i;
231	      end if;
232	
233	      -- Combinatorial outputs before the reset
234	      positionErr_o <= vPositionErr;
235	      alignErr_o    <= vAlignErr;
236	
237	      if (rst = '1') then
238	         v := REG_INIT_C;
239	      end if;
240	
241	      --
242	      rin <= v;
243	
244	      -- Output assignment
245	      sampleData_o      <= r.sampleData;
246	      sampleDataValid_o <= r.dataValid;
247	   -----------------------------------------------------------
248	   end process comb;
249	
250	   seq : process (clk) is
251	   begin
252	      if (rising_edge(clk)) then
253	         r <= rin after TPD_G;
254	      end if;
255	   end process seq;
256	   ---------------------------------------------------------------------
257	   ---------------------------------------------------------------------
258	
259	end architecture rtl;
